import React, { useState } from 'react';
import { motion } from 'framer-motion';
import { FiCheckCircle, FiAlertCircle, FiSend, FiGithub, FiLinkedin, FiMail, FiMapPin } from 'react-icons/fi';
import { useTheme } from '../ThemeContext';

const cv = { hidden:{opacity:0}, visible:{opacity:1,transition:{staggerChildren:0.09}} };
const ci = { hidden:{y:18,opacity:0}, visible:{y:0,opacity:1,transition:{type:'spring',stiffness:85,damping:16}} };

const info = [
    { icon:<FiMail size={16}/>,     label:'Email',    val:'barakusuma911@gmail.com',              href:'mailto:barakusuma911@gmail.com', color:'#6366f1' },
    { icon:<FiGithub size={16}/>,   label:'GitHub',   val:'github.com/BekaGensss',                href:'https://github.com/BekaGensss', color:'#818cf8' },
    { icon:<FiLinkedin size={16}/>, label:'LinkedIn', val:'linkedin.com/in/bara-kusuma',          href:'https://id.linkedin.com/in/bara-kusuma-707067294', color:'#22d3ee' },
    { icon:<FiMapPin size={16}/>,   label:'Lokasi',   val:'Indonesia',                            href:null, color:'#34d399' },
];

const Contact = () => {
    const { theme } = useTheme();
    const [form,  setForm]  = useState({ name:'', email:'', message:'' });
    const [errs,  setErrs]  = useState({});
    const [done,  setDone]  = useState(false);
    const [busy,  setBusy]  = useState(false);

    const change = e => {
        const { name, value } = e.target;
        setForm(p=>({...p,[name]:value}));
        if (errs[name]) setErrs(p=>({...p,[name]:''}));
    };

    const valid = () => {
        const e = {};
        if (!form.name.trim())    e.name    = 'Nama wajib diisi.';
        if (!form.email.trim())   e.email   = 'Email wajib diisi.';
        else if (!/\S+@\S+\.\S+/.test(form.email)) e.email = 'Format email tidak valid.';
        if (!form.message.trim()) e.message = 'Pesan wajib diisi.';
        setErrs(e);
        return !Object.keys(e).length;
    };

    const submit = async e => {
        e.preventDefault();
        if (!valid()) return;
        setBusy(true);
        try {
            const r = await fetch('https://getform.io/f/bjjrrgrb', {
                method:'POST', body:JSON.stringify(form),
                headers:{'Content-Type':'application/json',Accept:'application/json'},
            });
            if (r.ok) { setDone(true); setForm({name:'',email:'',message:''}); setTimeout(()=>setDone(false),6000); }
            else alert('Terjadi kesalahan. Coba lagi.');
        } catch { alert('Gagal terhubung.'); }
        finally { setBusy(false); }
    };

    return (
        <section id="contact" style={{ padding:'clamp(64px,10vh,96px) 0', position:'relative' }}>
            <div className="hdiv" style={{ marginBottom:'clamp(44px,6vh,64px)' }}/>
            <div style={{ maxWidth:1200, margin:'0 auto', padding:'0 24px' }}>

                {/* Header */}
                <motion.div initial={{y:20,opacity:0}} whileInView={{y:0,opacity:1}} transition={{duration:0.55}} viewport={{once:true}}
                    style={{ textAlign:'center', marginBottom:'clamp(32px,4.5vh,52px)' }}>
                    <span className="stag">Kontak</span>
                    <h2 style={{
                        fontFamily:'Outfit, sans-serif',
                        fontSize:'clamp(1.8rem,4.5vw,3rem)', fontWeight:900,
                        color:theme.textPrimary, letterSpacing:'-1.5px', marginBottom:12, lineHeight:1.1,
                    }}>
                        Mari{' '}
                        <span style={{
                            background:'linear-gradient(135deg,#a5b4fc,#6366f1,#22d3ee)',
                            WebkitBackgroundClip:'text', WebkitTextFillColor:'transparent', backgroundClip:'text',
                        }}>Berkolaborasi</span>
                    </h2>
                    <p style={{ fontSize:'clamp(13.5px,1.8vw,15px)', color:theme.textSecondary, maxWidth:440, margin:'0 auto' }}>
                        Ada ide atau proyek yang ingin dikerjakan bersama? Saya selalu siap mendengar.
                    </p>
                </motion.div>

                <motion.div initial="hidden" whileInView="visible" variants={cv} viewport={{once:true,amount:0.1}}
                    style={{ display:'grid', gridTemplateColumns:'repeat(auto-fit,minmax(270px,1fr))', gap:40, alignItems:'start' }}>

                    {/* Left */}
                    <motion.div variants={ci}>
                        <h3 style={{ fontFamily:'Outfit,sans-serif', fontSize:20, fontWeight:800, color:theme.textPrimary, marginBottom:6, letterSpacing:'-0.5px' }}>
                            Hubungi Langsung
                        </h3>
                        <p style={{ fontSize:14, color:theme.textSecondary, lineHeight:1.7, marginBottom:22 }}>
                            Pilih cara yang paling nyaman. Saya biasanya membalas dalam 24 jam.
                        </p>
                        <div style={{ display:'flex', flexDirection:'column', gap:10 }}>
                            {info.map(it => (
                                <motion.div key={it.label} variants={ci}>
                                    {it.href
                                        ? <a href={it.href} target={it.href.startsWith('http')?'_blank':undefined} rel="noopener noreferrer" style={{textDecoration:'none',display:'block'}}>
                                            <InfoCard item={it} theme={theme}/>
                                          </a>
                                        : <InfoCard item={it} theme={theme}/>
                                    }
                                </motion.div>
                            ))}
                        </div>
                    </motion.div>

                    {/* Right: Form */}
                    <motion.div variants={ci}>
                        {done && (
                            <motion.div initial={{y:-8,opacity:0,scale:0.97}} animate={{y:0,opacity:1,scale:1}}
                                style={{
                                    padding:'13px 16px', borderRadius:12, marginBottom:14,
                                    background:'rgba(52,211,153,0.08)', border:'1px solid rgba(52,211,153,0.25)',
                                    display:'flex', alignItems:'center', gap:10,
                                }}>
                                <FiCheckCircle size={17} style={{color:'#34d399',flexShrink:0}}/>
                                <div>
                                    <div style={{fontSize:13.5,fontWeight:700,color:'#6ee7b7'}}>Pesan terkirim!</div>
                                    <div style={{fontSize:12,color:theme.textMuted,marginTop:1}}>Saya akan segera membalas.</div>
                                </div>
                            </motion.div>
                        )}

                        <form onSubmit={submit} style={{
                            padding:'clamp(20px,3vw,28px)', borderRadius:20,
                            background:theme.bgCard, border:`1px solid ${theme.border}`,
                            backdropFilter:'blur(16px)',
                        }}>
                            {[
                                {id:'name',  label:'Nama Lengkap', type:'text',  ph:'John Doe'},
                                {id:'email', label:'Alamat Email',  type:'email', ph:'john@example.com'},
                            ].map(f=>(
                                <div key={f.id} style={{marginBottom:15}}>
                                    <label htmlFor={f.id} style={{display:'block',fontSize:13,fontWeight:600,color:theme.textPrimary,marginBottom:6}}>
                                        {f.label}
                                    </label>
                                    <input id={f.id} type={f.type} name={f.id}
                                        value={form[f.id]} onChange={change} placeholder={f.ph}
                                        className={`finput${errs[f.id]?' err':''}`}
                                        style={{background:theme.inputBg,borderColor:errs[f.id]?'rgba(244,63,94,0.5)':theme.inputBorder,color:theme.inputText}}
                                    />
                                    {errs[f.id] && <p style={{marginTop:5,fontSize:12,color:'#f87171',display:'flex',alignItems:'center',gap:4}}><FiAlertCircle size={12}/>{errs[f.id]}</p>}
                                </div>
                            ))}
                            <div style={{marginBottom:22}}>
                                <label htmlFor="message" style={{display:'block',fontSize:13,fontWeight:600,color:theme.textPrimary,marginBottom:6}}>Pesan</label>
                                <textarea id="message" name="message" rows={5}
                                    value={form.message} onChange={change}
                                    placeholder="Halo Bara, saya ingin berdiskusi mengenai..."
                                    className={`finput${errs.message?' err':''}`}
                                    style={{resize:'vertical',minHeight:110,background:theme.inputBg,borderColor:errs.message?'rgba(244,63,94,0.5)':theme.inputBorder,color:theme.inputText}}
                                />
                                {errs.message&&<p style={{marginTop:5,fontSize:12,color:'#f87171',display:'flex',alignItems:'center',gap:4}}><FiAlertCircle size={12}/>{errs.message}</p>}
                            </div>
                            <button type="submit" disabled={busy} className="btn-p" style={{width:'100%',justifyContent:'center',opacity:busy?0.7:1}}>
                                {busy
                                    ? <><span style={{display:'inline-block',width:14,height:14,border:'2px solid rgba(255,255,255,0.3)',borderTopColor:'white',borderRadius:'50%',animation:'spin 0.7s linear infinite'}}/><span>Mengirim...</span></>
                                    : <><span>Kirim Pesan</span><FiSend size={14}/></>
                                }
                            </button>
                            <style>{`@keyframes spin{to{transform:rotate(360deg)}}`}</style>
                        </form>
                    </motion.div>
                </motion.div>
            </div>
        </section>
    );
};

const InfoCard = ({ item, theme }) => (
    <div style={{
        padding:'11px 15px', borderRadius:13,
        background:theme.bgCard, border:`1px solid ${theme.border}`,
        display:'flex', alignItems:'center', gap:12,
        transition:'all 0.25s ease', cursor:item.href?'pointer':'default',
    }}
        onMouseEnter={e=>{ if(item.href){ e.currentTarget.style.background=`${item.color}0e`; e.currentTarget.style.borderColor=`${item.color}30`; e.currentTarget.style.transform='translateX(5px)'; } }}
        onMouseLeave={e=>{ e.currentTarget.style.background=theme.bgCard; e.currentTarget.style.borderColor=theme.border; e.currentTarget.style.transform='translateX(0)'; }}
    >
        <div style={{ width:36,height:36,borderRadius:10,background:`${item.color}15`,border:`1px solid ${item.color}25`,display:'flex',alignItems:'center',justifyContent:'center',color:item.color,flexShrink:0 }}>
            {item.icon}
        </div>
        <div>
            <div style={{ fontSize:10.5,color:theme.textMuted,fontWeight:700,textTransform:'uppercase',letterSpacing:0.8,marginBottom:1 }}>{item.label}</div>
            <div style={{ fontSize:13.5,color:theme.textPrimary,fontWeight:500 }}>{item.val}</div>
        </div>
    </div>
);

export default Contact;