import React, { useState, useEffect } from 'react';
import { ThemeProvider, useTheme } from './ThemeContext';
import Navbar from './components/Navbar';
import Hero from './components/Hero';
import About from './components/About';
import Projects from './components/Projects';
import GitHubRepos from './components/GitHubRepos';
import Contact from './components/Contact';
import Footer from './components/Footer';

/* ── Premium Loading Screen ── */
const Loader = () => {
    const [progress, setProgress] = useState(0);

    useEffect(() => {
        const interval = setInterval(() => {
            setProgress(p => {
                if (p >= 100) { clearInterval(interval); return 100; }
                const step = p < 60 ? Math.random() * 12 + 4 : Math.random() * 6 + 2;
                return Math.min(p + step, 100);
            });
        }, 120);
        return () => clearInterval(interval);
    }, []);

    return (
        <div style={{
            position: 'fixed', inset: 0, zIndex: 9999,
            background: '#050508',
            display: 'flex', flexDirection: 'column',
            alignItems: 'center', justifyContent: 'center',
            gap: 0,
        }}>
            {/* Ambient glow */}
            <div style={{
                position: 'absolute', width: 400, height: 400, borderRadius: '50%',
                background: 'radial-gradient(circle, rgba(99,102,241,0.12) 0%, transparent 70%)',
                filter: 'blur(40px)', pointerEvents: 'none',
            }} />

            {/* Logo mark */}
            <div style={{ position: 'relative', marginBottom: 32 }}>
                <svg width="72" height="72" viewBox="0 0 72 72">
                    <circle cx="36" cy="36" r="30" fill="none"
                        stroke="rgba(99,102,241,0.12)" strokeWidth="2" />
                    <circle cx="36" cy="36" r="30" fill="none"
                        stroke="url(#lg-loader)" strokeWidth="2"
                        strokeDasharray={`${progress * 1.885} 188.5`}
                        strokeLinecap="round"
                        style={{ transition: 'stroke-dasharray 0.12s ease', transformOrigin: '50% 50%', transform: 'rotate(-90deg)' }}
                    />
                    <defs>
                        <linearGradient id="lg-loader" x1="0%" y1="0%" x2="100%" y2="100%">
                            <stop offset="0%" stopColor="#6366f1" />
                            <stop offset="100%" stopColor="#22d3ee" />
                        </linearGradient>
                    </defs>
                </svg>
                <div style={{
                    position: 'absolute', inset: 14,
                    borderRadius: '50%',
                    background: 'linear-gradient(135deg, #6366f1, #4f46e5)',
                    display: 'flex', alignItems: 'center', justifyContent: 'center',
                    fontFamily: 'Outfit, sans-serif', fontWeight: 900, fontSize: 22,
                    color: '#fff', letterSpacing: '-1px',
                    boxShadow: '0 0 24px rgba(99,102,241,0.5)',
                }}>B</div>
            </div>

            {/* Progress bar */}
            <div style={{ width: 160, height: 2, background: 'rgba(255,255,255,0.06)', borderRadius: 2, overflow: 'hidden', marginBottom: 16 }}>
                <div style={{
                    height: '100%',
                    width: `${progress}%`,
                    background: 'linear-gradient(90deg, #6366f1, #22d3ee)',
                    borderRadius: 2,
                    transition: 'width 0.12s ease',
                }} />
            </div>

            <span style={{
                fontFamily: 'Inter, sans-serif', fontSize: 11, fontWeight: 600,
                color: 'rgba(248,250,252,0.3)', letterSpacing: 3, textTransform: 'uppercase',
            }}>{progress < 100 ? 'Loading' : 'Ready'}</span>
        </div>
    );
};

const AppContent = () => {
    const { isDark } = useTheme();
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        const t = setTimeout(() => setLoading(false), 2000);
        return () => clearTimeout(t);
    }, []);

    const bg = isDark
        ? 'radial-gradient(ellipse 80% 55% at 0% 0%,rgba(99,102,241,0.1) 0%,transparent 55%), radial-gradient(ellipse 60% 45% at 100% 100%,rgba(34,211,238,0.06) 0%,transparent 55%), #050508'
        : 'radial-gradient(ellipse 80% 55% at 0% 0%,rgba(99,102,241,0.08) 0%,transparent 55%), #f0f4ff';

    return (
        <>
            <div style={{
                opacity: loading ? 1 : 0, pointerEvents: loading ? 'all' : 'none',
                transition: 'opacity 0.6s ease', position: 'fixed', inset: 0, zIndex: 9999,
            }}>
                <Loader />
            </div>
            <div style={{ minHeight: '100vh', background: bg, transition: 'background 0.4s', display: 'flex', flexDirection: 'column' }}>
                <Navbar />
                <main style={{ flex: 1 }}>
                    <Hero />
                    <About />
                    <Projects />
                    <GitHubRepos />
                    <Contact />
                </main>
                <Footer />
            </div>
        </>
    );
};

const App = () => (
    <ThemeProvider><AppContent /></ThemeProvider>
);
export default App;